import React from 'react';
import '../App.css';

class Ride extends React.Component {
  render() {
    return (
      <section className="bike">
        <img src={this.props.image} alt="bike" className="icaro" style={{ right: `${this.props.style}px` }} />
      </section>
    )
  }
}

export default Ride
